import React, { useState } from "react";
import { Container, Navbar, Nav, Button, Form, Card } from "react-bootstrap";
import { Link } from "react-router-dom";
import logo from "./images/logo.jpeg";
import "./home2.css";

function HomePage() {
  const [wordsIKindaKnow, setWordsIKindaKnow] = useState([
    "apple",
    "banana",
    "cat",
    "dog"
  ]);
  const [wordsIDontKnow, setWordsIDontKnow] = useState([
    "caset",
    "vreemon",
    "cremora"
  ]);
  const [wordsIKnow, setWordsIKnow] = useState([]);
  const [currentWord, setCurrentWord] = useState("");
  const [userInput, setUserInput] = useState("");
  const [gameStarted, setGameStarted] = useState(false);
  const [message, setMessage] = useState("");

  const startGame = () => {
    if (wordsIDontKnow.length > 0) {
      setCurrentWord(wordsIDontKnow[0]);
    } else if (wordsIKindaKnow.length > 0) {
      setCurrentWord(wordsIKindaKnow[0]);
    } else {
      setMessage("No words left to spell!");
      return;
    }
    setGameStarted(true);
    setMessage("");
  };

  const checkSpelling = () => {
    if (!currentWord) return;
    if (userInput.toLowerCase() === currentWord.toLowerCase()) {
      setWordsIKnow([...wordsIKnow, currentWord]);
      setWordsIDontKnow(wordsIDontKnow.filter((word) => word !== currentWord));
      setWordsIKindaKnow(wordsIKindaKnow.filter((word) => word !== currentWord));
      setMessage("Correct! 🎉");
    } else {
      setMessage("Incorrect! Try again. ❌");
    }
    setUserInput("");
    updateNextWord();
  };

  const updateNextWord = () => {
    if (wordsIDontKnow.length > 0) {
      setCurrentWord(wordsIDontKnow[0]);
    } else if (wordsIKindaKnow.length > 0) {
      setCurrentWord(wordsIKindaKnow[0]);
    } else {
      setCurrentWord("none");
      setMessage("Game Over! 🎉");
      setGameStarted(false);
    }
  };

  return (
    <div className="app">
      <Navbar bg="light" variant="light" expand="lg">
        <Container>
          <Navbar.Brand href="#home">
            <img
              src={logo}
              width="30"
              height="30"
              className="d-inline-block align-top"
              alt="React Bootstrap logo"
            />
          </Navbar.Brand>
          <Navbar.Toggle aria-controls="basic-navbar-nav" />
          <Navbar.Collapse id="basic-navbar-nav">
            <Nav className="me-auto">
              <Nav.Link as={Link} to="/home">Home</Nav.Link>
              <Nav.Link as={Link} to="/">Login</Nav.Link>
              <Nav.Link as={Link} to="/register">Registration</Nav.Link>
            </Nav>
          </Navbar.Collapse>
        </Container>
      </Navbar>

      <Container className="text-center mt-4">
        <h1 className="big-title">Smart Tutor Spelling Game</h1>
        {gameStarted ? (
          <Card className="p-4 text-center">
            <h2>Spell this word:</h2>
            <h3 className="text-primary">{currentWord}</h3>
            <Form.Control
              type="text"
              value={userInput}
              onChange={(e) => setUserInput(e.target.value)}
              placeholder="Type your answer here"
              className="my-3"
            />
            <Button onClick={checkSpelling} variant="success">Submit</Button>
            <p className="mt-3">{message}</p>
          </Card>
        ) : (
          <Button onClick={startGame} variant="primary" className="mt-3">
            Start Game
          </Button>
        )}
      </Container>
    </div>
  );
}

export default HomePage;
